def ExecuteConvertToUTC(self,args,env):
        if args.ContainsKey('DateFormat'):
            dateFormat=args['DateFormat']
        else:
            dateFormat="yyyy-MM-ddTHH:mm:ssZ"

        if args.ContainsKey("LocalDateTime"):
            datetime = args['LocalDateTime']
        else:
            datetime=System.DateTime.Now

        zone = self.Account.GetTimeZoneInfoOrDefault(args["Timezone"])
        value = zone.ConvertToUtc(ServiceDesk.Common.ParseDateTime(datetime)).ToString(dateFormat)
        return {'ConvertedDate':value}

def ExecuteConvertFromUTC(self,args,env):
        if args.ContainsKey('DateFormat'):
            dateFormat=args['DateFormat']
        else:
            dateFormat="yyyy-MM-ddTHH:mm:ssZ"

        if args.ContainsKey("DateTime"):
            datetime = args['DateTime']
        else:
            datetime=System.DateTime.UtcNow

        zone = self.Account.GetTimeZoneInfoOrDefault(args["Timezone"])
        value = zone.ConvertFromUtc(datetime).ToString(dateFormat)
        return {'ConvertedDate':value}

