-- ============================================================
-- STEP 1: Delete from child table first (IBMSAlarmTransactionMaster)
--         to avoid FK constraint violations
-- ============================================================
BEGIN TRANSACTION;

BEGIN TRY

    -- Delete transactions linked to old escalated alarms
    DELETE atm
    FROM IBMSAlarmTransactionMaster atm
    INNER JOIN IBMSEscalatedAlarms ea 
        ON atm.AlarmEscalationKey = ea.AlarmEscalationKey
    WHERE ea.AlarmDateTime < @CutoffDate;

    PRINT CONCAT('IBMSAlarmTransactionMaster: ', @@ROWCOUNT, ' rows deleted.');

    -- ============================================================
    -- STEP 2: Delete from parent table (IBMSEscalatedAlarms)
    -- ============================================================
    DELETE FROM IBMSEscalatedAlarms
    WHERE AlarmDateTime < @CutoffDate;

    PRINT CONCAT('IBMSEscalatedAlarms: ', @@ROWCOUNT, ' rows deleted.');

    Delete from IBMSDXEscalatedAlarmMap
    where AlarmEscalationKey not in (select AlarmEscalationKey from IBMSEscalatedAlarms)

    PRINT CONCAT('IBMSDXEscalatedAlarmMap: ', @@ROWCOUNT, ' rows deleted.');

    delete from IBMSAlarmDXMaster
    PRINT CONCAT('IBMSAlarmDXMaster: ', @@ROWCOUNT, ' rows deleted.');


    COMMIT TRANSACTION;
    PRINT 'Transaction committed successfully.';

END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
    PRINT 'Error occurred. Transaction rolled back.';
    PRINT CONCAT('Error Message: ', ERROR_MESSAGE());
    PRINT CONCAT('Error Line: ',    ERROR_LINE());
END CATCH;

